#!/usr/bin/env node
// Reads node_modules/leaflet/dist/{leaflet.css,leaflet.js} and the
// leaflet.markercluster bundle and emits libs/services/pilgrimage/leaflet-assets.ts
// so the WebView map can run without fetching from a CDN. Runs automatically
// via the `postinstall` hook; the generated file is gitignored.

import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');
const cssPath = resolve(root, 'node_modules/leaflet/dist/leaflet.css');
const jsPath = resolve(root, 'node_modules/leaflet/dist/leaflet.js');
const mcCorePath = resolve(root, 'node_modules/leaflet.markercluster/dist/MarkerCluster.css');
const mcThemePath = resolve(
  root,
  'node_modules/leaflet.markercluster/dist/MarkerCluster.Default.css'
);
const mcJsPath = resolve(root, 'node_modules/leaflet.markercluster/dist/leaflet.markercluster.js');
const outPath = resolve(root, 'libs/services/pilgrimage/leaflet-assets.ts');

// Defensive escapes so the inlined strings can't terminate their own host tag
// in the WebView HTML, even if a future Leaflet bump introduces such a sequence.
const escapeStyle = (s) => s.replace(/<\/style>/gi, '<\\/style>');
const escapeScript = (s) => s.replace(/<\/script>/gi, '<\\/script>');

const css = escapeStyle(readFileSync(cssPath, 'utf8'));
const js = escapeScript(readFileSync(jsPath, 'utf8'));

// MarkerCluster files are optional at the bundler level — if the dep hasn't
// been installed yet (e.g. a partial install) we emit empty strings so the app
// still builds; the cluster code in the WebView no-ops without them.
const readIfExists = (p) => (existsSync(p) ? readFileSync(p, 'utf8') : '');
const mcCss = escapeStyle(readIfExists(mcCorePath) + '\n' + readIfExists(mcThemePath));
const mcJs = escapeScript(readIfExists(mcJsPath));

const banner =
  '// AUTO-GENERATED by scripts/bundle-leaflet.mjs — do not edit.\n' +
  '// Regenerated on `bun install` via the postinstall hook.\n\n';

const body =
  `export const LEAFLET_CSS = ${JSON.stringify(css)};\n\n` +
  `export const LEAFLET_JS = ${JSON.stringify(js)};\n\n` +
  `export const LEAFLET_MARKERCLUSTER_CSS = ${JSON.stringify(mcCss)};\n\n` +
  `export const LEAFLET_MARKERCLUSTER_JS = ${JSON.stringify(mcJs)};\n`;

mkdirSync(dirname(outPath), { recursive: true });
writeFileSync(outPath, banner + body);

const kb = (n) => `${(n / 1024).toFixed(1)}KB`;
console.log(
  `bundle-leaflet: wrote ${outPath} (leaflet css ${kb(css.length)}, js ${kb(js.length)}, ` +
    `markercluster css ${kb(mcCss.length)}, js ${kb(mcJs.length)})`
);
